  actHike:{it:"Escursione in Val Masino",en:"Hike in Val Masino",es:"Excursión en Val Masino",fr:"Randonnée en Val Masino",de:"Wandern im Val Masino"},
  actHikeD:{it:"Classico della Valle di Mello: da San Martino all'Alpe Pioda su un sentiero pianeggiante tra prati di granito e torrenti. Adatto anche ai più giovani. A circa 45 min in auto.",en:"Valle di Mello classic: San Martino to Alpe Pioda on a flat valley-floor path through granite meadows and stream crossings. Fine for younger hikers. About 45 min by car.",es:"Clásico de Valle di Mello: de San Martino a Alpe Pioda por un sendero llano entre prados de granito y arroyos. Bien para los más jóvenes. A unos 45 min en coche.",fr:"Classique de la Valle di Mello: de San Martino à l'Alpe Pioda sur un sentier plat, prairies de granite et torrents. Convient aussi aux plus jeunes. Environ 45 min en voiture.",de:"Valle-di-Mello-Klassiker: von San Martino zur Alpe Pioda auf flachem Talbodenweg durch Granitwiesen und Bäche. Auch für jüngere geeignet. Etwa 45 Min. mit dem Auto."},
  hikeLink:{it:"Sentiero Valle di Mello",en:"Valle di Mello trail",es:"Ruta Valle di Mello",fr:"Sentier Valle di Mello",de:"Valle-di-Mello-Weg"},
  actHikeDiff:{it:"Facile · pianeggiante",en:"Easy · flat",es:"Fácil · llano",fr:"Facile · plat",de:"Leicht · flach"},
