  actHikeBeginner:{it:"Fondo valle pianeggiante. Va bene anche per i più giovani.",en:"Flat valley floor. Fine for younger hikers too.",es:"Fondo de valle llano. Bien también para los más jóvenes.",fr:"Fond de vallée plat. Convient aussi aux plus jeunes.",de:"Flacher Talboden. Auch für jüngere geeignet."},
  actLagazzuolo:{it:"Escursione al Lago Lagazzuolo",en:"Lago Lagazzuolo hike",es:"Excursión al Lago Lagazzuolo",fr:"Randonnée au Lago Lagazzuolo",de:"Wanderung zum Lago Lagazzuolo"},
  actLagazzuoloD:{it:"Andata e ritorno ripida da San Giuseppe in Valmalenco fino a un lago alpino turchese. Circa 5 km, 620 m di dislivello, 3–3,5 ore. Vale la pena per il colore dell'acqua. A circa 40 min in auto.",en:"Steep out-and-back from San Giuseppe in Valmalenco to a turquoise alpine lake. About 5 km, 620 m gain, 3–3.5 hours. Worth it for the colour of the water. About 40 min by car.",es:"Ida y vuelta empinada desde San Giuseppe en Valmalenco hasta un lago alpino turquesa. Unos 5 km, 620 m de desnivel, 3–3,5 horas. Merece la pena por el color del agua. A unos 40 min en coche.",fr:"Aller-retour raide depuis San Giuseppe en Valmalenco jusqu'à un lac alpin turquoise. Environ 5 km, 620 m de dénivelé, 3–3,5 h. Ça vaut le détour pour la couleur de l'eau. Environ 40 min en voiture.",de:"Steiler Hin-und-zurück von San Giuseppe in der Valmalenco zu einem türkisen Bergsee. Etwa 5 km, 620 Höhenmeter, 3–3,5 Stunden. Lohnt sich für die Wasserfarbe. Etwa 40 Min. mit dem Auto."},
  lagazzuoloLink:{it:"Sentiero Lago Lagazzuolo",en:"Lago Lagazzuolo trail",es:"Ruta Lago Lagazzuolo",fr:"Sentier Lago Lagazzuolo",de:"Lago-Lagazzuolo-Weg"},
  actLagazzuoloDiff:{it:"Difficile · ripida",en:"Hard · steep",es:"Difícil · empinada",fr:"Difficile · raide",de:"Schwer · steil"},
  actLagazzuoloGear:{it:"Scarpe da trekking; bastoncini utili in discesa.",en:"Hiking shoes; poles helpful on the descent.",es:"Zapatos de trekking; bastones útiles en el descenso.",fr:"Chaussures de randonnée ; bâtons utiles à la descente.",de:"Wanderschuhe; Stöcke hilfreich beim Abstieg."},
  actLagazzuoloBeginner:{it:"Meglio dopo una camminata più facile in valle, o andate con calma.",en:"Better after an easier valley walk, or take it slow.",es:"Mejor después de un paseo más fácil por el valle, o id con calma.",fr:"Mieux après une balade plus facile en vallée, ou prenez votre temps.",de:"Besser nach einer leichteren Talwanderung, oder langsam angehen."},
  actFellaria:{it:"Escursione al Ghiacciaio Fellaria",en:"Ghiacciaio Fellaria Hike",es:"Excursión al Ghiacciaio Fellaria",fr:"Randonnée au Ghiacciaio Fellaria",de:"Wanderung zum Ghiacciaio Fellaria"},
  actFellariaD:{it:"Laguna glaciale con iceberg, grotte di ghiaccio e cascate sopra Campo Moro in Valmalenco. Parcheggio a Campo Moro; belvedere già al Rifugio Bignami, oppure continuate fino alla laguna. Circa 1 h in auto.",en:"Glacier lagoon with icebergs, ice caves and waterfalls above Campo Moro in Valmalenco. Park at Campo Moro; glacier views from Rifugio Bignami, or keep going to the lagoon. About 1 h by car.",es:"Laguna glaciar con icebergs, cuevas de hielo y cascadas sobre Campo Moro en Valmalenco. Aparcad en Campo Moro; vistas del glaciar desde Rifugio Bignami, o seguid hasta la laguna. A unos 1 h en coche.",fr:"Lagune glaciaire avec icebergs, grottes de glace et cascades au-dessus de Campo Moro en Valmalenco. Parking à Campo Moro ; vue sur le glacier depuis le Rifugio Bignami, ou continuez jusqu'à la lagune. Environ 1 h en voiture.",de:"Gletscherlagune mit Eisbergen, Eishöhlen und Wasserfällen oberhalb von Campo Moro in der Valmalenco. Parken in Campo Moro; Gletscherblick schon am Rifugio Bignami, oder weiter zur Lagune. Etwa 1 Std. mit dem Auto."},
  fellariaLink:{it:"Guida Fellaria",en:"Fellaria hike guide",es:"Guía Fellaria",fr:"Guide Fellaria",de:"Fellaria-Wanderführer"},
  actFellariaDiff:{it:"Media · potete accorciarla",en:"Moderate · shorten as you like",es:"Media · se puede acortar",fr:"Modérée · raccourcissez à volonté",de:"Mittel · nach Belieben kürzen"},
  actFellariaGear:{it:"Scarpe da trekking, bastoncini. La strada per Campo Moro è stretta e tortuosa; partite presto. Per la laguna, una traccia GPS aiuta.",en:"Hiking shoes, poles. The road up to Campo Moro is narrow and winding; start early. A GPS track helps if you continue to the lagoon.",es:"Zapatos de trekking, bastones. La carretera a Campo Moro es estrecha y sinuosa; salid temprano. Un track GPS ayuda si seguís hasta la laguna.",fr:"Chaussures de randonnée, bâtons. La route vers Campo Moro est étroite et sinueuse ; partez tôt. Une trace GPS aide si vous continuez jusqu'à la lagune.",de:"Wanderschuhe, Stöcke. Die Straße nach Campo Moro ist eng und kurvig; früh starten. Ein GPS-Track hilft auf dem Weg zur Lagune."},
  actFellariaBeginner:{it:"Parcheggiate a Campo Moro e salite al Rifugio Bignami (meno di un'ora): dietro il rifugio c'è già un belvedere sul ghiacciaio. Se volete, continuate sul Percorso Glaciologico C fino alla laguna. Non salite sul ghiaccio.",en:"Park at Campo Moro and walk up to Rifugio Bignami (under an hour): behind the hut you already get a big glacier view. Keep going on Percorso Glaciologico C to the lagoon if you want more. Stay off the ice.",es:"Aparcad en Campo Moro y subid al Rifugio Bignami (menos de una hora): detrás del refugio ya hay una gran vista del glaciar. Seguid por el Percorso Glaciologico C hasta la laguna si queréis más. No subáis al hielo.",fr:"Garez-vous à Campo Moro et montez au Rifugio Bignami (moins d'une heure) : derrière le refuge, belle vue sur le glacier. Continuez sur le Percorso Glaciologico C jusqu'à la lagune si vous voulez. Restez hors de la glace.",de:"In Campo Moro parken und zum Rifugio Bignami (unter einer Stunde): hinter der Hütte schon ein großer Gletscherblick. Wer will, weiter auf Percorso Glaciologico C zur Lagune. Nicht aufs Eis."},
  actClimb:{it:"Arrampicata al Sasso Remenno",en:"Rock climbing at Sasso Remenno",es:"Escalada en Sasso Remenno",fr:"Escalade au Sasso Remenno",de:"Klettern am Sasso Remenno"},
  actClimbD:{it:"Il più grande monolite di granito d'Europa in Val Masino — decine di vie, dalle placche per principianti fino al 9a. A circa 45 min in auto.",en:"Europe's largest granite monolith in Val Masino — dozens of routes from beginner slabs to steep 9a. About 45 min by car.",es:"El mayor monolito de granito de Europa en Val Masino — decenas de vías, de placas para principiantes al 9a. A unos 45 min en coche.",fr:"Le plus grand monolithe de granite d'Europe en Val Masino — des dizaines de voies, des dalles débutants au 9a. Environ 45 min en voiture.",de:"Europas größter Granitmonolith im Val Masino — Dutzende Routen von Anfängerplatten bis 9a. Etwa 45 Min. mit dem Auto."},
  climbLink:{it:"Sasso Remenno",en:"Sasso Remenno",es:"Sasso Remenno",fr:"Sasso Remenno",de:"Sasso Remenno"},
